// Helper to check if API Key is valid
function getGeminiApiKey(headers?: any): string | null {
  const customKey = headers && headers["x-gemini-key"] ? headers["x-gemini-key"] : null;
  if (customKey && customKey.trim() !== "" && customKey !== "null" && customKey !== "undefined") {
    return customKey;
  }
  const key = process.env.GEMINI_API_KEY;
  if (!key || key === "MY_GEMINI_API_KEY" || key.trim() === "") {
    return null;
  }
  return key;
}

// Smart local fallback generator in case Gemini is not configured or fails
function getMockFuturologyData(niche: string, focus: string, targetYear: number, macroVars: any, targetType?: string, targetDateStr?: string) {
  const currentYear = 2026;
  const target = targetYear;
  const isMicro = targetType === "micro";

  const aiOptFactor = macroVars.aiAdoptionSpeed / 100;
  const climatePessFactor = macroVars.climateRiskScale / 100;
  const tradeProtFactor = macroVars.protectionism / 100;

  // Let's calculate some probabilities
  const optProbHist = Math.round(Math.max(15, 65 * aiOptFactor - 15 * climatePessFactor - 20 * tradeProtFactor));
  const optProbSpec = Math.round(Math.max(10, 80 * aiOptFactor - 10 * tradeProtFactor));
  const optProbWeighted = Math.round((optProbHist * 0.4) + (optProbSpec * 0.6));

  const pessProbHist = Math.round(Math.max(20, 60 * climatePessFactor + 30 * tradeProtFactor - 20 * aiOptFactor));
  const pessProbSpec = Math.round(Math.max(15, 75 * climatePessFactor + 25 * tradeProtFactor - 15 * aiOptFactor));
  const pessProbWeighted = Math.round((pessProbHist * 0.4) + (pessProbSpec * 0.6));

  const baseProbHist = Math.max(10, 100 - optProbWeighted - pessProbWeighted);
  const baseProbSpec = Math.max(10, 100 - optProbWeighted - pessProbWeighted);
  const baseProbWeighted = Math.round((baseProbHist * 0.5) + (baseProbSpec * 0.5));

  const displayTarget = isMicro && targetDateStr ? targetDateStr : `${targetYear}`;

  const event1Year = isMicro ? 2026 : Math.round((currentYear + targetYear) / 2);
  const event1Title = isMicro ? "Marcos Táticos Iniciais" : "Integração Híbrida de Sistemas Inteligentes";
  const event1Desc = isMicro
    ? `Adoção incremental inicial neste subsetor de ${niche}. Resposta tática inicial no prazo imediato conforme flutuações.`
    : `Adoção em massa de agentes autônomos que reduzem custos operacionais no nicho de ${niche} em até 40% com base nos ajustes de capital.`;

  const event2Year = isMicro ? 2026 : target;
  const event2Title = isMicro ? "Consolidação Curta e Resultados" : "Sintonia de Alta Performance e Abundância";
  const event2Desc = isMicro
    ? `Análise consolidada no ciclo alvo curto apontado de: "${displayTarget}". Os primeiros resultados reais de impacto para o foco "${focus}" são medidos.`
    : `Estabilização de novos modelos de negócios que prosperam com foco em ${focus}, otimizados por análises quantitativas autônomas em tempo real.`;

  return {
    niche,
    researchFocus: focus,
    targetYear,
    targetType: targetType || "macro",
    targetDateStr: targetDateStr || String(targetYear),
    createdAt: new Date().toISOString(),
    macroVariables: macroVars,
    scenarioSummary: `Análise prospectiva para o nicho de ${niche.toUpperCase()} com foco em "${focus}". Sob as variáveis macroeconômicas vigentes (Velocidade de IA: ${macroVars.aiAdoptionSpeed}%, Protecionismo: ${macroVars.protectionism}%), projetamos três eixos de evolução à data alvo (${displayTarget}).`,
    branches: {
      optimistic: {
        branchType: "optimistic",
        branchTitle: "Eixo de Aceleração Disruptiva",
        probabilityHistorical: optProbHist,
        probabilitySpeculative: optProbSpec,
        weightedProbability: optProbWeighted,
        description: `Cenário onde a rápida adoção da Inteligência Artificial (${macroVars.aiAdoptionSpeed}%) age como catalisador de crescimento rápido, superando barreiras burocráticas e impulsionando inovações estruturais em curto espaço de tempo em ${niche}.`,
        events: [
          {
            year: event1Year,
            eventTitle: `Fase Inicial: ${event1Title}`,
            description: event1Desc,
            socioeconomicImpact: Math.round(70 + 20 * aiOptFactor),
            technologicalImpact: Math.round(80 + 15 * aiOptFactor)
          },
          {
            year: event2Year,
            eventTitle: `Meta Alvo (${displayTarget}): ${event2Title}`,
            description: event2Desc,
            socioeconomicImpact: Math.round(85 + 10 * aiOptFactor),
            technologicalImpact: Math.round(95 + 5 * aiOptFactor)
          }
        ]
      },
      baseline: {
        branchType: "baseline",
        branchTitle: "Eixo de Transição Linear",
        probabilityHistorical: baseProbHist,
        probabilitySpeculative: baseProbSpec,
        weightedProbability: baseProbWeighted,
        description: `A evolução do nicho de ${niche} segue uma trajetória ponderada e estável, com absorção gradual de tecnologias e adaptações econômicas moderadas até o fim da previsão.`,
        events: [
          {
            year: event1Year,
            eventTitle: "Regulamentação e Padronização",
            description: `Esforço de adaptação local para padronizar as práticas para ${focus}, trazendo segurança regulatória inicial mas impondo leve amortecimento no curto prazo.`,
            socioeconomicImpact: 60,
            technologicalImpact: 65
          },
          {
            year: event2Year,
            eventTitle: `Maturação Estável (${displayTarget})`,
            description: `Consolidação das diretrizes de inovação. Stakeholders e novos players adaptam-se aos novos índices de inflação (${macroVars.inflationRate}%) e juros (${macroVars.interestRates}%).`,
            socioeconomicImpact: 70,
            technologicalImpact: 75
          }
        ]
      },
      pessimistic: {
        branchType: "pessimistic",
        branchTitle: "Eixo de Fricção Tecnológica e Climática",
        probabilityHistorical: pessProbHist,
        probabilitySpeculative: pessProbSpec,
        weightedProbability: pessProbWeighted,
        description: `Cenário onde pressões climáticas elevadas (${macroVars.climateRiskScale}%), protecionismo global (${macroVars.protectionism}%) e fricção no mercado dificultam a inovação no setor de ${niche}.`,
        events: [
          {
            year: event1Year,
            eventTitle: "Surgimento de Gargalos Operacionais",
            description: `Tensões políticas e desastres de escassez de hardware aumentam o custo logístico imediato de infraestrutura física requerida para os projetos de ${focus}.`,
            socioeconomicImpact: Math.round(35 - 15 * climatePessFactor),
            technologicalImpact: Math.round(50 - 10 * tradeProtFactor)
          },
          {
            year: event2Year,
            eventTitle: `Estagnação Tática e Custos de Defesa (${displayTarget})`,
            description: `O nicho de ${niche} opera sob alta restrição protecionista regional, com baixa liquidez (reflexo de juros de ${macroVars.interestRates}%) e fragmentação tecnológica internacional marcando o fim do ciclo de alvo.`,
            socioeconomicImpact: Math.round(30 - 20 * climatePessFactor),
            technologicalImpact: Math.round(45 - 15 * tradeProtFactor)
          }
        ]
      }
    },
    expertOpinion: `O desenvolvimento tático de ${niche} planejado para a data alvo (${displayTarget}) com foco em ${focus} dependerá essencialmente da velocidade de adaptação a este novo ecossistema. Com juros atuais de capital de risco em ${macroVars.interestRates}%, soluções de baixo toque que automatizem ou usem IA localmente ganham tração massiva e imediata.`,
    aiHunch: `Se eu tivesse que apostar minhas engrenagens, eu diria que o foco "${focus}" em ${niche} vai avançar de modo brutal devido à velocidade de IA de ${macroVars.aiAdoptionSpeed}%. Mas bota uma coisa na cabeça: se os juros de ${macroVars.interestRates}% insistirem em estrangular a captação tradicional, quem não automatizar até a máquina de café vai virar fóssil histórico antes do previsto. Minha aposta analítica? Menos slides e mais bots executores imediatos no chão de fábrica!`
  };
}

